patch:
diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index 756b25ac9856..0cf11177aa6d 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -20951,9 +20951,14 @@ bool SLPVectorizerPass::vectorizeGEPIndices(BasicBlock *BB, BoUpSLP &R) {
       // initially collected them or their index is optimized to constant value.
       // If so, they are marked as deleted, so remove them from the set of
       // candidates.
-      Candidates.remove_if([&R](Value *I) {
-        return R.isDeleted(cast<Instruction>(I)) ||
-               isa<Constant>(cast<GetElementPtrInst>(I)->idx_begin()->get());
+      Candidates.remove_if([&](Value *V) {
+        auto *GEP = cast<GetElementPtrInst>(V);
+        if (R.isDeleted(GEP) || isa<Constant>(GEP->idx_begin()->get()))
+          return true;
+        if (auto *IdxI = dyn_cast<Instruction>(GEP->idx_begin()->get()))
+          if (IdxI->getParent() != BB)
+            return true;
+        return false;
       });

       // Remove from the set of candidates all pairs of getelementptrs with

